import anthropic

client = anthropic.Anthropic()

def run_agent(user_message: str, tools: list) -> str:
    messages = [{"role": "user", "content": user_message}]

    while True:
        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=4096,
            tools=tools,
            messages=messages,
        )
        # Always append the full assistant turn (may contain text + tool_use blocks)
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            return next(b.text for b in response.content if hasattr(b, "text"))

        # stop_reason == "tool_use" — collect and execute all tool_use blocks
        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                result = dispatch_tool(block.name, block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result,
                })

        messages.append({"role": "user", "content": tool_results})

def run_agent_robust(user_message: str, tools: list) -> str:
    messages = [{"role": "user", "content": user_message}]
    MAX_TURNS = 15

    for turn in range(MAX_TURNS):
        response = client.messages.create(
            model="claude-sonnet-4-6", max_tokens=4096,
            tools=tools, messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            texts = [b.text for b in response.content if hasattr(b, "text")]
            return " ".join(texts)

        if response.stop_reason == "max_tokens":
            # Partial response — model hit token limit
            raise RuntimeError("Response truncated: increase max_tokens or shorten history")

        if response.stop_reason == "stop_sequence":
            texts = [b.text for b in response.content if hasattr(b, "text")]
            return " ".join(texts)  # treat as complete

        if response.stop_reason == "tool_use":
            tool_results = []
            for block in response.content:
                if block.type == "tool_use":
                    result = dispatch_tool(block.name, block.input)
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": result,
                    })
            messages.append({"role": "user", "content": tool_results})
            continue

        raise RuntimeError(f"Unexpected stop_reason: {response.stop_reason}")

    raise RuntimeError(f"Agent did not finish within {MAX_TURNS} turns")

import anthropic
import asyncio

async_client = anthropic.AsyncAnthropic()

async def run_agent_async(user_message: str, tools: list) -> str:
    messages = [{"role": "user", "content": user_message}]

    for _ in range(15):
        response = await async_client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=4096,
            tools=tools,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            return next(b.text for b in response.content if hasattr(b, "text"))

        if response.stop_reason == "tool_use":
            # Execute all tools concurrently within the turn
            tool_uses = [b for b in response.content if b.type == "tool_use"]
            results = await asyncio.gather(*(
                async_dispatch_tool(tu.name, tu.input) for tu in tool_uses
            ))
            tool_results = [
                {"type": "tool_result", "tool_use_id": tu.id, "content": r}
                for tu, r in zip(tool_uses, results)
            ]
            messages.append({"role": "user", "content": tool_results})

    raise RuntimeError("Agent loop did not terminate")

def prune_tool_results(messages: list, keep_last: int = 3) -> list:
    """
    Replace tool_result content in older turns with a compact placeholder.
    Keeps the last `keep_last` tool turns intact so the model has recent context.
    """
    tool_turns = [
        i for i, m in enumerate(messages)
        if m["role"] == "user" and isinstance(m["content"], list)
        and any(isinstance(c, dict) and c.get("type") == "tool_result" for c in m["content"])
    ]
    # Prune all but the last keep_last tool turns
    for idx in tool_turns[:-keep_last]:
        pruned = []
        for block in messages[idx]["content"]:
            if isinstance(block, dict) and block.get("type") == "tool_result":
                pruned.append({**block, "content": "[result pruned]"})
            else:
                pruned.append(block)
        messages[idx] = {**messages[idx], "content": pruned}
    return messages

