from dataclasses import dataclass, field

@dataclass
class LoopMetrics:
    turns: int = 0
    input_tokens: list[int] = field(default_factory=list)
    output_tokens: list[int] = field(default_factory=list)

    def record(self, response) -> None:
        self.turns += 1
        self.input_tokens.append(response.usage.input_tokens)
        self.output_tokens.append(response.usage.output_tokens)

    def report(self) -> dict:
        return {
            "turns": self.turns,
            "total_input_tokens": sum(self.input_tokens),
            "total_output_tokens": sum(self.output_tokens),
            "input_per_turn": self.input_tokens,
        }

def run_agent_with_metrics(user_message: str, tools: list):
    messages = [{"role": "user", "content": user_message}]
    metrics = LoopMetrics()

    for _ in range(15):
        response = client.messages.create(
            model="claude-sonnet-4-6", max_tokens=4096,
            tools=tools, messages=messages,
        )
        metrics.record(response)
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            text = next(b.text for b in response.content if hasattr(b, "text"))
            return text, metrics.report()

        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                result = dispatch_tool(block.name, block.input)
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result,
                })
        messages.append({"role": "user", "content": tool_results})

    raise RuntimeError("Max turns exceeded")

